// Determine which slot fired based on UTC hour
const hour = new Date().getUTCHours();
// Noon fires ~18:50 UTC; Evening ~02:50 UTC
const slot = (hour >= 16 && hour <= 22) ? 'Noon' : 'Evening';
const playlistName = 'KAZM Request ' + slot + ' Playlist';
const playlistPath = '/Charles Helstein/MegaSegDropbox/MegaSeg copy/Playlists/KAZM Request ' + slot + ' Playlist';
return [{ json: { slot, playlistName, playlistPath } }];

// Maintain a played-set in static data so we don't repeat songs
const sd = $getWorkflowStaticData('global');
sd.played = sd.played || [];

const slotData = $('Determine Slot').first().json;
const boardData = $('Fetch Request Board').first().json;
// Board returns newest-first, so oldest unfulfilled = last element
const recent = boardData.requests || [];

const playedSet = new Set(sd.played);
let pick = null;
for (let i = recent.length - 1; i >= 0; i--) {
  const r = recent[i];
  const key = (String(r.title || '') + '|' + String(r.artist || '')).toLowerCase().trim();
  if (!playedSet.has(key)) { pick = r; break; }
}

if (pick) {
  const key = (String(pick.title || '') + '|' + String(pick.artist || '')).toLowerCase().trim();
  sd.played.push(key);
  if (sd.played.length > 200) sd.played = sd.played.slice(-200);
}

return [{ json: {
  slot: slotData.slot,
  playlistName: slotData.playlistName,
  playlistPath: slotData.playlistPath,
  found: !!pick,
  title: pick ? String(pick.title || '') : '',
  artist: pick ? String(pick.artist || '') : ''
} }];

const HEADER = 'Name\tArtist\tComposer\tAlbum\tGenre\tSize\tTime\tDisc Number\tDisc Count\tTrack Number\tTrack Count\tYear\tDate Modified\tDate Added\tBit Rate\tSample Rate\tVolume Adjustment\tKind\tEqualizer\tComments\tPlays\tLast Played\tMy Rating\tLocation\tUniqueID';

const req = $('Pick Oldest Unplayed Request').first().json;
const reqTitle = String(req.title || '').trim().toLowerCase();
const reqArtist = String(req.artist || '').trim().toLowerCase();
const playlistPath = req.playlistPath;
const playlistName = req.playlistName;

let raw = '';
try {
  const buf = await this.helpers.getBinaryDataBuffer(0, 'data');
  raw = buf.toString('utf8');
} catch (e) {}

const clean = (s) => String(s || '').replace(/\([^)]*\)/g, '').replace(/\s+/g, ' ').trim().toLowerCase();
const toSecs = (t) => {
  const p = String(t || '').split(':').map(Number);
  if (!p.length || p.some(isNaN)) return 0;
  return p.reduce((a, b) => a * 60 + b, 0);
};
const toRow = (f) => {
  const c = new Array(25).fill('');
  c[0] = f['01']; c[1] = f['02'] || ''; c[3] = f['09'] || '';
  c[4] = String(f['06'] || '').split('/')[0];
  c[6] = toSecs(f['05']).toFixed(2);
  c[11] = f['10'] || ''; c[20] = f['14'] || '0'; c[21] = f['15'] || ''; c[22] = '0';
  c[23] = f['49']; c[24] = f['45'];
  return c.join('\t');
};

let match = null;
if (raw.startsWith('D**')) {
  for (const rec of raw.split('99* ----').slice(1)) {
    const f = {};
    for (const line of rec.split('\n')) {
      const m = line.match(/^(\d\d)\]\s?(.*)/);
      if (m) f[m[1]] = m[2].replace(/\r$/, '');
    }
    if (!f['01'] || !f['49'] || !f['45']) continue;
    const t = clean(f['01']);
    const a = clean(f['02']);
    const tMatch = t === reqTitle || t.includes(reqTitle) || reqTitle.includes(t);
    const aMatch = !reqArtist || a.includes(reqArtist) || reqArtist.includes(a);
    if (tMatch && aMatch) { match = f; break; }
  }
}

const playlistContent = match ? HEADER + '\n' + toRow(match) + '\n' : HEADER + '\n';

return [{ json: {
  playlistPath, playlistName, playlistContent,
  songFound: !!match,
  songTitle: match ? match['01'] : req.title,
  songArtist: match ? (match['02'] || '') : req.artist
} }];

const sd = $getWorkflowStaticData('global');
const d = $('Search Library and Build Playlist').first().json;
sd.log = sd.log || [];
sd.log.unshift({
  at: new Date().toISOString(),
  slot: d.playlistName,
  song: d.songTitle,
  artist: d.songArtist,
  foundInLib: d.songFound
});
sd.log = sd.log.slice(0, 50);
return [{ json: { ok: true, slot: d.playlistName, song: d.songTitle, artist: d.songArtist, foundInLibrary: d.songFound } }];
